    def _validate_cart_items(self, cart_items):
        if not isinstance(cart_items, list):
            raise CheckoutError("Cart items must be a list.")
        if not cart_items:
            raise CheckoutError("Cart cannot be empty.")

        validated_items = []
        for item in cart_items:
            if not isinstance(item, Item):
                raise CheckoutError(f"Invalid item found in cart: {item}")
            if item.quantity <= 0 or item.price <= 0:
                raise CheckoutError(f"Item {item.name} has invalid quantity or price.")
            validated_items.append(item)

        cart_total = sum(item.get_total() for item in validated_items)
        return {"items": validated_items, "subtotal": cart_total}

    def _apply_discount_codes(self, validated_cart, user, discount_codes_to_apply=None):
        subtotal = validated_cart["subtotal"]
        final_total_after_discounts = subtotal
        applied_discounts = []
        discount_messages = []

        if discount_codes_to_apply:
            if not isinstance(discount_codes_to_apply, list):
                raise CheckoutError("Discount codes to apply must be a list.")

            for code_str in discount_codes_to_apply:
                if not isinstance(code_str, str) or not code_str:
                    discount_messages.append(f"Skipping invalid discount code: '{code_str}'")
                    continue

                discount_code = self.available_discount_codes.get(code_str)
                if not discount_code:
                    discount_messages.append(f"Discount code '{code_str}' not found.")
                    continue

                is_applicable, reason = discount_code.is_applicable(user, subtotal)
                if not is_applicable:
                    discount_messages.append(f"Discount code '{code_str}' not applicable: {reason}")
                else:
                    new_total = discount_code.apply(final_total_after_discounts)
                    final_total_after_discounts = new_total
                    applied_discounts.append({"code": code_str, "discount_percentage": discount_code.discount_percentage, "amount_before": subtotal})
                    discount_messages.append(f"Discount code '{code_str}' applied.")

        return {
            "processed_cart": validated_cart,
            "user": user,
            "subtotal_before_discounts": subtotal,
            "total_after_discounts": final_total_after_discounts,
            "applied_discounts": applied_discounts,
            "discount_messages": discount_messages
        }

    def _calculate_tax(self, discounted_cart_data):
        total_after_discounts = discounted_cart_data["total_after_discounts"]
        tax_amount = total_after_discounts * self.tax_rate
        final_total = total_after_discounts + tax_amount

        return {
            "discounted_cart_data": discounted_cart_data,
            "tax_rate": self.tax_rate,
            "tax_amount": tax_amount,
            "final_total": final_total
        }

